import React, { useState, useEffect, useRef } from "react";
import { NavLink, useNavigate } from "react-router-dom";
import UserRegister from "../users/userRegister";
import Login from "../users/Login";
import "../App.css";

export default function Navbar() {
  const role = localStorage.getItem("role");
  const navigate = useNavigate();

  const [showLogin, setShowLogin] = useState(false);
  const [showRegister, setShowRegister] = useState(false);
  const [openProfileMenu, setOpenProfileMenu] = useState(false);

  const menuRef = useRef();
  const user = JSON.parse(localStorage.getItem("user"));

  const handleLogout = () => {
    localStorage.clear();
    navigate("/");
    window.location.reload();
  };

  // Close dropdown on outside click
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (menuRef.current && !menuRef.current.contains(event.target)) {
        setOpenProfileMenu(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Hide navbar for admin roles
  if (role === "Admin" || role === "Academic Panel") {
    return null;
  }

  // 🔥 Styled link functions
  const studentLink = (active) =>
    `rounded-md px-3 py-2 text-xs font-bold uppercase tracking-[0.15em] transition-colors ${
      active
        ? "bg-cyan-700 text-white"
        : "bg-cyan-50 text-cyan-900 hover:bg-cyan-100"
    }`;

  return (
    <nav className="fixed top-0 left-0 w-full bg-white/95 backdrop-blur border-b shadow-sm z-50">
      <div className="max-w-7xl mx-auto px-6 py-3">

        {/* TOP ROW */}
        {/* <div className="flex justify-between items-center mb-2"> */}
          <h1 className="text-lg font-extrabold uppercase tracking-[0.2em] text-cyan-900">
            Smart Learning
          </h1>

          {/* RIGHT SIDE */}
          <div className="flex items-center space-x-4">

            {/* NOT LOGGED IN */}
            {!role && (
              <>
                <button
                  onClick={() => setShowLogin(true)}
                  className="border px-4 py-1 rounded"
                >
                  Login
                </button>

                <button
                  onClick={() => setShowRegister(true)}
                  className="bg-cyan-600 text-white px-4 py-1 rounded"
                >
                  Sign Up
                </button>
              </>
            )}

            {/* LOGGED IN USER */}
            {role && (
              <div className="relative" ref={menuRef}>
                <img
                  src={
                    user?.profileImage ||
                    "https://ui-avatars.com/api/?name=User&background=0D8ABC&color=fff"
                  }
                  alt="profile"
                  onClick={() => setOpenProfileMenu(!openProfileMenu)}
                  className="w-10 h-10 rounded-full cursor-pointer border-2 border-cyan-600"
                />

                {openProfileMenu && (
                  <div className="absolute right-0 mt-2 w-48 bg-white text-black rounded-lg shadow-lg overflow-hidden">
                    <button
                      onClick={() => {
                        setOpenProfileMenu(false);
                        navigate("/profile");
                      }}
                      className="block w-full text-left px-4 py-2 hover:bg-gray-100"
                    >
                      Manage Profile
                    </button>

                    <button
                      onClick={handleLogout}
                      className="block w-full text-left px-4 py-2 hover:bg-gray-100 text-red-500"
                    >
                      Logout
                    </button>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        {/* NAV LINKS */}
        <div className="flex flex-wrap items-center gap-4">

          {/* GUEST LINKS */}
          {!role && (
            <>
              <button onClick={() => window.scrollTo({ top: 0, behavior: "smooth" })}>
                Home
              </button>
              <button onClick={() => window.dispatchEvent(new CustomEvent("scroll-about"))}>
                About
              </button>
              <button onClick={() => window.dispatchEvent(new CustomEvent("scroll-contact"))}>
                Contact
              </button>
            </>
          )}

          {/* 🔥 STUDENT LINKS (UPDATED STYLE) */}
          {role === "Student" && (
            <div className="flex flex-wrap items-center gap-2">
              <span className="text-[10px] font-bold uppercase tracking-widest text-slate-400">
                Student
              </span>

              <NavLink to="/dashboard" className={({ isActive }) => studentLink(isActive)}>
                Dashboard
              </NavLink>

              <NavLink to="/tasks" className={({ isActive }) => studentLink(isActive)}>
                Tasks
              </NavLink>

              <NavLink to="/quiz-bank" className={({ isActive }) => studentLink(isActive)}>
                Quiz Bank
              </NavLink>

              <NavLink to="/chatbot" className={({ isActive }) => studentLink(isActive)}>
                Chatbot
              </NavLink>

              {/* NEW LINKS */}
              <NavLink to="/resources" className={({ isActive }) => studentLink(isActive)}>
                Resources
              </NavLink>

              <NavLink
                to="/credits"
                className={({ isActive }) =>
                  isActive
                    ? "rounded-md px-3 py-2 text-xs font-bold uppercase bg-emerald-600 text-white"
                    : "rounded-md px-3 py-2 text-xs font-bold uppercase bg-emerald-50 text-emerald-900 hover:bg-emerald-100"
                }
              >
                Credits
              </NavLink>

              <NavLink
                to="/reviews"
                className={({ isActive }) =>
                  isActive
                    ? "rounded-md px-3 py-2 text-xs font-bold uppercase bg-amber-600 text-white"
                    : "rounded-md px-3 py-2 text-xs font-bold uppercase bg-amber-50 text-amber-900 hover:bg-amber-100"
                }
              >
                Reviews
              </NavLink>

              <NavLink
                to="/sessions"
                className={({ isActive }) =>
                  isActive
                    ? "rounded-md px-3 py-2 text-xs font-bold uppercase bg-sky-600 text-white"
                    : "rounded-md px-3 py-2 text-xs font-bold uppercase bg-sky-50 text-sky-900 hover:bg-sky-100"
                }
              >
                Sessions
              </NavLink>
            </div>
          )}
        </div>
      {/* </div> */}

      {/* LOGIN MODAL */}
      {showLogin && (
        <div className="fixed inset-0 flex items-center justify-center z-50">
          <div
            className="absolute inset-0 bg-black/40"
            onClick={() => setShowLogin(false)}
          />
          <Login closeModal={() => setShowLogin(false)} />
        </div>
      )}

      {/* REGISTER MODAL */}
      {showRegister && (
        <div className="fixed inset-0 flex items-center justify-center z-50">
          <div
            className="absolute inset-0 bg-black/40"
            onClick={() => setShowRegister(false)}
          />
          <UserRegister closeModal={() => setShowRegister(false)} />
        </div>
      )}
    </nav>
  );
}
